    case 25: return G[5] * ykl + G[6];
    case 26: return G[5];
    case 27: return G[7];
    case 28: return G[7] * ykl + G[8];
    case 29: return G[7];
    case 30: return G[6];
    case 31: return G[6] * ykl + G[7];
    case 32: return G[6];
    case 33: return G[5];
    case 34: return G[5] * ykl + G[6];
    case 35: return G[5];
    case 36: return G[0];
    case 37: return G[0] * ykl + G[1];
    case 38: return G[0];
    case 39: return G[1];
    case 40: return G[1] * ykl + G[2];
    case 41: return G[1];
    case 42: return G[0];
    case 43: return G[0] * ykl + G[1];
    case 44: return G[0];
    case 45: return G[2];
    case 46: return G[2] * ykl + G[3];
    case 47: return G[2];
    case 48: return G[1];
    case 49: return G[1] * ykl + G[2];
    case 50: return G[1];
    case 51: return G[0];
    case 52: return G[0] * ykl + G[1];
    case 53: return G[0];
    default: return 0.0;
  }
}

